import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





const MAX_COMMENTS = 500;
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;


export default function Component(props: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 3,
    features: [] as string[],
    comments: '',
  });

  const [errors, setErrors] = useState({ name: '', email: '' });

  const validateStep1 = () => {
    const newErrors = {
      name: formData.name.trim() ? '' : 'Name is required',
      email: EMAIL_REGEX.test(formData.email) ? '' : 'Valid email is required',
    };
    setErrors(newErrors);
    return !newErrors.name && !newErrors.email;
  };

  const submit = useAction<ActionSubmitPayload>('submit');

  const handleNext = () => {
    if (step === 1 && !validateStep1()) return;
    setStep((s) => s + 1);
  };

  const handleBack = () => setStep((s) => s - 1);

  const handleSubmit = () => {
    submit({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments,
    });
  };

  const isNextDisabled = step === 1 && (!formData.name || !EMAIL_REGEX.test(formData.email));

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={2}>Customer Survey</Heading>
        <Progress value={(step - 1) * 25} max={75} showLabel={false} />
        <Text variant="label">Step {step} of 4</Text>

        <Card padding="var(--ggui-spacing-6)">
          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Input
                label="Name"
                value={formData.name}
                onChange={(val) => setFormData({ ...formData, name: val })}
                error={errors.name}
              />
              <Input
                label="Email"
                type="email"
                value={formData.email}
                onChange={(val) => setFormData({ ...formData, email: val })}
                error={errors.email}
              />
            </Stack>
          )}

          {step === 2 && (
            <RadioGroup
              label="How satisfied are you?"
              value={formData.satisfaction.toString()}
              onChange={(val) => setFormData({ ...formData, satisfaction: parseInt(val) })}
              options={props.satisfactionLabels.map((label, i) => ({
                value: (i + 1).toString(),
                label: `${i + 1}: ${label}`,
              }))}
            />
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="label">Feature Interests</Text>
              {props.featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={formData.features.includes(feature)}
                  onChange={(checked) =>
                    setFormData((prev) => ({
                      ...prev,
                      features: checked ? [...prev.features, feature] : prev.features.filter((f) => f !== feature),
                    }))
                  }
                />
              ))}
            </Stack>
          )}

          {step === 4 && (
            <TextArea
              label="Additional Comments"
              value={formData.comments}
              onChange={(val) => setFormData({ ...formData, comments: val })}
              maxLength={MAX_COMMENTS}
              showCount
              rows={4}
            />
          )}

          {step === 5 && (
            <Stack gap="var(--ggui-spacing-3)">
              <Heading level={4}>Review Your Answers</Heading>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Satisfaction: {props.satisfactionLabels[formData.satisfaction - 1]}</Text>
              <Text>Features: {formData.features.join(', ') || 'None'}</Text>
              <Text>Comments: {formData.comments || 'No comments'}</Text>
            </Stack>
          )}
        </Card>

        <Row gap="var(--ggui-spacing-4)" justify="between">
          <Button variant="secondary" onClick={handleBack} disabled={step === 1}>Back</Button>
          {step < 4 ? (
            <Button onClick={handleNext} disabled={isNextDisabled}>Next</Button>
          ) : step === 4 ? (
            <Button onClick={() => setStep(5)}>Review</Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>Submit</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

