import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable } from '@ggui-ai/design/interact';
import { MotionKeyframes } from '@ggui-ai/design/primitives';

import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };





// Helper sub-components
const PriorityBadge = (props: { priority: 'low' | 'medium' | 'high' }) => {
  const color =
    props.priority === 'high'
      ? 'var(--ggui-color-error-500)'
      : props.priority === 'medium'
      ? 'var(--ggui-color-warning-500)'
      : 'var(--ggui-color-success-500)';
  return <Badge variant="default" style={{ color }}>{props.priority}</Badge>;
};

export default function Component(props: Props) {
  const [tasks, setTasks] = useState(props.tasks || []);
  const [addingTask, setAddingTask] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'create' || action === 'edit' || action === 'move') {
        setTasks((prev) => {
          const filtered = prev.filter((t) => t.id !== task?.id);
          return task ? [...filtered, task] : filtered;
        });
      } else if (action === 'delete') {
        setTasks((prev) => prev.filter((t) => t.id !== task?.id));
      }
    }
  }, [taskChanged.latest]);

  const handleMove = (taskId: string, newColumn: string) => {
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t)));
  };

  const handleCreate = (columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      column: columnId,
      assignee: '??',
    };
    taskUpdate({ action: 'create', taskId: newTask.id, data: { ...newTask } } as any);
    setTasks([...tasks, newTask]);
    setNewTaskTitle('');
    setAddingTask(null);
  };

  const stats = useMemo(() => {
    const total = tasks.length;
    const done = tasks.filter((t) => t.column === 'done').length;
    return { total, done };
  }, [tasks]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-4)">
        <Row justify="between" align="center">
          <Heading level={1}>Kanban Board</Heading>
          <Box background="var(--ggui-color-surfaceVariant)" padding="var(--ggui-spacing-3)" borderRadius="var(--ggui-shape-radius-md)">
            <Text>Tasks: {stats.total} | Completed: {stats.done}</Text>
          </Box>
        </Row>
        <Row gap="var(--ggui-spacing-4)" align="start">
          {props.columns.map((col) => (
            <Card key={col.id} shadow="sm" padding="var(--ggui-spacing-4)" style={{ flex: 1 }}>
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={4}>{col.name} ({tasks.filter((t) => t.column === col.id).length})</Heading>
                {tasks.filter((t) => t.column === col.id).map((task) => (
                  <Card key={task.id} padding="var(--ggui-spacing-3)" border={true}>
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text variant="body">{task.title}</Text>
                      <Row justify="between" align="center">
                        <PriorityBadge priority={task.priority || 'medium'} />
                        <Dropdown
                          trigger={<Button variant="ghost" size="sm">Move</Button>}
                          options={props.columns
                            .filter((c) => c.id !== task.column)
                            .map((c) => ({ value: c.id!, label: c.name! }))}
                          value=""
                          onChange={(newCol) => handleMove(task.id!, newCol)}
                        />
                      </Row>
                    </Stack>
                  </Card>
                ))}
                {addingTask === col.id ? (
                  <Box padding="var(--ggui-spacing-2)" background="var(--ggui-color-surfaceVariant)">
                    <Input label="Title" value={newTaskTitle} onChange={setNewTaskTitle} />
                    <Select label="Priority" value={newTaskPriority} onChange={(v) => setNewTaskPriority(v as any)} options={[{value:'low', label:'Low'},{value:'medium', label:'Medium'},{value:'high', label:'High'}]} />
                    <Button onClick={() => handleCreate(col.id!)} fullWidth>Add</Button>
                  </Box>
                ) : (
                  <Button variant="outline" onClick={() => setAddingTask(col.id!)} fullWidth>+ Add Task</Button>
                )}
              </Stack>
            </Card>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

