// Place helper components here if needed

const CATEGORIES = [
  { name: 'Alkali Metal', color: 'var(--ggui-color-primary-300)' },
  { name: 'Alkaline Earth Metal', color: 'var(--ggui-color-success-200)' },
  { name: 'Transition Metal', color: 'var(--ggui-color-warning-200)' },
  { name: 'Post-transition Metal', color: 'var(--ggui-color-info-200)' },
  { name: 'Metalloid', color: 'var(--ggui-color-error-200)' },
  { name: 'Reactive Nonmetal', color: 'var(--ggui-color-primary-100)' },
  { name: 'Noble Gas', color: 'var(--ggui-color-primary-400)' },
  { name: 'Lanthanide', color: 'var(--ggui-color-neutral-300)' },
  { name: 'Actinide', color: 'var(--ggui-color-neutral-400)' },
];

const getCategoryColor = (category?: string) =>
  CATEGORIES.find((c) => c.name === category)?.color || 'var(--ggui-color-surfaceVariant)';

export default function Component(props: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selected, setSelected] = useState<(typeof props.elements)[0] | null>(null);

  const filtered = useMemo(() => {
    const term = searchTerm.toLowerCase();
