          {filtered.map((el) => (
            <Card
              key={el.atomicNumber}
              as={Clickable}
              onClick={() => setSelected(el)}
              style={{
                gridRow: el.row,
                gridColumn: el.col,
                background: getCategoryColor(el.category),
                padding: 'var(--ggui-spacing-1)',
                textAlign: 'center',
                aspectRatio: '1/1',
              }}
            >
              <Text variant="caption" style={{ textAlign: 'left' }}>{el.atomicNumber}</Text>
              <Heading level={5}>{el.symbol}</Heading>
            </Card>
          ))}
        </Box>

        {selected && (
          <Card padding="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={3}>{selected.name} ({selected.symbol})</Heading>
              <Text>Atomic Number: {selected.atomicNumber}</Text>
              <Text>Atomic Weight: {selected.atomicWeight}</Text>
              <Text>Category: {selected.category}</Text>
            </Stack>
          </Card>
        )}

        <Card padding="var(--ggui-spacing-4)">
