const RatingStars = ({ rating }: { rating: number }) => (
  <Row gap="var(--ggui-spacing-1)">
    {[1, 2, 3, 4, 5].map((i) => (
      <Icon key={i} name={i <= rating ? 'star' : 'star-outline'} size={16} color={i <= rating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'} aria-hidden="true" />
    ))}
  </Row>
);


export default function Component(props: Props) {
  const addToCart = useAction<ActionAddToCartPayload>('addToCart');
  const [quantity, setQuantity] = useState(1);

  const [activeTab, setActiveTab] = useState('description');

  const product = props.product;
  const stock = product.stock || 0;
  const isOutOfStock = stock === 0;

  const handleAddToCart = () => {
    if (product.id) {
      addToCart({ productId: product.id, quantity });
    }
  };

  const specs = (product.specifications || []) as { key: string; value: string }[];
  const reviews = (product.reviews || []) as { author: string; rating: number; text: string; date: string }[];

  const tabs = [
    { key: 'description', label: 'Description', content: <Text>{product.description}</Text> },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Table
          columns={[
            { key: 'key', header: 'Feature' },
            { key: 'value', header: 'Details' },
          ]}
          data={specs}
        />
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack gap="var(--ggui-spacing-4)">
          {reviews.map((r, i) => (
            <Card key={i} padding="var(--ggui-spacing-3)" border>
              <Row justify="between">
                <Text variant="label">{r.author}</Text>
                <Text variant="caption">{r.date}</Text>
              </Row>
              <RatingStars rating={r.rating} />
              <Text variant="bodySmall">{r.text}</Text>
            </Card>
          ))}
        </Stack>
      ),
    },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        <Row gap="var(--ggui-spacing-8)" wrap>
          <Box borderRadius="var(--ggui-shape-radius-lg)" background="var(--ggui-color-surfaceVariant)" padding="var(--ggui-spacing-10)" width="400px" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Heading level={3}>{product.name}</Heading>
          </Box>
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1 }}>
            <Heading level={1}>{product.name}</Heading>
            <Text variant="bodyLarge" weight="bold">{`${product.currency}${product.price}`}</Text>
            <RatingStars rating={product.rating || 0} />
            <Badge variant={stock > 0 ? 'success' : 'error'}>
              {stock > 0 ? (stock <= 5 ? 'Low Stock' : 'In Stock') : 'Out of Stock'}
            </Badge>
          </Stack>
        </Row>

        <Card padding="var(--ggui-spacing-4)">
          <Tabs items={tabs} activeKey={activeTab} onChange={setActiveTab} />
        </Card>

        <Row gap="var(--ggui-spacing-4)" align="center">
          <Box padding="var(--ggui-spacing-2)" border borderRadius="var(--ggui-shape-radius-md)">
            <Row align="center" gap="var(--ggui-spacing-2)">
              <Button as={Clickable} variant="ghost" onClick={() => setQuantity(q => Math.max(1, q - 1))}>-</Button>
              <Text>{quantity}</Text>
              <Button as={Clickable} variant="ghost" onClick={() => setQuantity(q => Math.min(stock, q + 1))}>+</Button>
            </Row>
          </Box>

          <Button variant="primary" disabled={isOutOfStock} onClick={handleAddToCart}>
            {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
          </Button>
        </Row>

      </Stack>
    </Container>


  );
}

