const MessageBubble = ({ sender, text, timestamp, isOwn }: { sender: string; text: string; timestamp: string; isOwn: boolean }) => (
  <Stack align={isOwn ? 'end' : 'start'} gap="var(--ggui-spacing-1)">
    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
      {sender} • {new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
