);


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag
  const [messages, setMessages] = useState(() => props.messages || []);
  const [inputValue, setInputValue] = useState('');
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (message.latest) {
      setMessages((prev) => [...prev, message.latest as any]);
    }
  }, [message.latest]);

  useEffect(() => {
    if (typing.latest?.sender) {
      setTypingUsers((prev) => {
        const next = new Set(prev);
        if (typing.latest?.active) next.add(typing.latest.sender!);
        else next.delete(typing.latest.sender!);
        return next;
      });
    }
  }, [typing.latest]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, typingUsers]);

  const handleSend = useCallback(() => {
    if (!inputValue.trim()) return;
    const timestamp = new Date().toISOString();
    sendMessage({ text: inputValue, timestamp });
    setMessages((prev) => [...prev, { sender: props.currentUser, text: inputValue, timestamp }]);
    setInputValue('');
  }, [inputValue, props.currentUser, sendMessage]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      {/* implement your UI here */}
    <Container maxWidth="md" padding="var(--ggui-spacing-4)">
      <Card padding="var(--ggui-spacing-4)">
        <Stack gap="var(--ggui-spacing-4)">
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3}>{props.title}</Heading>
              <Badge variant="default">{props.participantCount} Participants</Badge>
            </Stack>
            {typingUsers.size > 0 && (
              <Text variant="caption" color="var(--ggui-color-primary-600)">
                {Array.from(typingUsers).join(', ')} {typingUsers.size > 1 ? 'are' : 'is'} typing...
              </Text>
            )}
          </Row>
          <Divider />
          <Box
            ref={scrollRef as any}
            padding="var(--ggui-spacing-2)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
            style={{ height: '400px', overflowY: 'auto' }}
          >
            <Stack gap="var(--ggui-spacing-4)">
              {messages.map((m, i) => {
                const isOwn = m.sender === props.currentUser;
                return (
                  <MessageBubble
                    key={i}
                    sender={m.sender || 'Unknown'}
                    text={m.text || ''}
                    timestamp={m.timestamp || new Date().toISOString()}
                    isOwn={isOwn}
                  />
                );
              })}
            </Stack>
          </Box>
          <Row gap="var(--ggui-spacing-2)" align="center">
            <Box style={{ flex: 1 }}>
              <Input
                label="Message"
                value={inputValue}
                onChange={setInputValue}
                placeholder="Type a message..."
                onKeyDown={(e: any) => e.key === 'Enter' && handleSend()}
              />
            </Box>
            <Button
              variant="primary"
              disabled={!inputValue.trim()}
              onClick={handleSend}
            >
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>


  );
}

