  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





const AVATARS = ['😀', '😎', '👩‍💻', '👨‍💼'];
const ROLES = ['Developer', 'Designer', 'Manager', 'Other'];


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding
  const [isProcessing, setIsProcessing] = useState(false);
  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile?.name || '');
  const [email, setEmail] = useState(props.initialProfile?.email || '');
  const [avatar, setAvatar] = useState(props.initialProfile?.avatar || props.avatarOptions[0] || '');
  const [role, setRole] = useState(props.initialProfile?.role || props.roleOptions[0] || '');

  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile?.theme || 'Light');

  const isValidEmail = (email: string) => /\S+@\S+\.\S+/.test(email);
  const canGoNext = useMemo(() => {
    if (step === 1) return name.trim() !== '' && isValidEmail(email);
    return true;
  }, [step, name, email]);

  const onComplete = async () => {
    setIsProcessing(true);
    await complete({ name, email, avatar, role, emailNotifications, theme });
    setIsProcessing(false);
  };


  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Row justify="between">
            <Text variant="label">Step {step} of 3</Text>
            <Text variant="label">{Math.round((step / 3) * 100)}% Complete</Text>
          </Row>
          <Progress value={(step / 3) * 100} size="md" />
        </Stack>

        <Card padding="var(--ggui-spacing-6)" shadow="md">
          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Profile Setup</Heading>
              <Input label="Name" value={name} onChange={setName} required />
              <Input label="Email" value={email} onChange={setEmail} type="email" error={email && !isValidEmail(email) ? 'Invalid email format' : undefined} required />
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label">Avatar</Text>
                <Row gap="var(--ggui-spacing-2)">
                  {props.avatarOptions.map((a) => (
                    <Box key={a} as={Hoverable}>
                      <Box as={Clickable} onClick={() => setAvatar(a)} padding="var(--ggui-spacing-2)" borderRadius="var(--ggui-shape-radius-md)" border={avatar === a ? '2px solid var(--ggui-color-primary-600)' : '2px solid transparent'}>
                        <Text size="3xl">{a}</Text>
                      </Box>
                    </Box>
                  ))}
                </Row>

              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Preferences</Heading>
              <Select label="Role" value={role} onChange={setRole} options={props.roleOptions.map(r => ({ value: r, label: r })) as any} />



              <Checkbox label="Enable email notifications" checked={emailNotifications} onChange={setEmailNotifications} />
              <Toggle label={`Theme: ${theme}`} checked={theme === 'Dark'} onChange={(checked) => setTheme(checked ? 'Dark' : 'Light')} />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review & Confirm</Heading>
              <Stack gap="var(--ggui-spacing-2)">
                <Text><b>Name:</b> {name}</Text>
                <Text><b>Email:</b> {email}</Text>
                <Text><b>Avatar:</b> {avatar}</Text>
                <Text><b>Role:</b> {role}</Text>
                <Text><b>Notifications:</b> {emailNotifications ? 'On' : 'Off'}</Text>
                <Text><b>Theme:</b> {theme}</Text>
              </Stack>
            </Stack>
          )}
        </Card>

        <Row gap="var(--ggui-spacing-4)" justify="between">
          <Button variant="outline" onClick={() => setStep(s => Math.max(1, s - 1))} disabled={step === 1}>Go Back</Button>
          {step < 3 ? (
            <Button onClick={() => setStep(s => Math.min(3, s + 1))} disabled={!canGoNext}>Next</Button>
          ) : (
            <Button variant="primary" onClick={onComplete} disabled={isProcessing}>{isProcessing ? 'Processing...' : 'Complete Setup'}</Button>
          )}

        </Row>
      </Stack>
    </Container>


  );
}
